import _ from 'lodash';
import dayjs from 'dayjs';
import { ActionTree } from 'vuex';
import { uuid } from 'vue-uuid';
import { type, characterType } from '@/data/constans';
import {
  SET_CURRENTDATA,
  DELETE_CURRENTDATA,
  SAVE_MY_CARD,
  SET_MY_CARD,
  SAVE_HOME_ACTIVE_NAME,
  SET_CALCULATOR_INITDATA,
  DELETE_CALCULATOR_INITDATA,
  SET_CALCULATOR_GENERALDATA,
  SET_CALCULATOR_EXTREMITYDATA,
} from './mutation-types';

const actions: ActionTree<any, any> = {
  navigationTab({ commit }: any, name: string) {
    commit(SAVE_HOME_ACTIVE_NAME, name);
  },
  selectCard({ state, commit }: any, user: {
    num: number, type: string, name: string,
    levelXiu: number, levelDu: number, levelJu: number, juChecked: boolean
  }) {
    const { currentData } = state;
    const newData = [...currentData];
    const oldRen = _.find(currentData[user.num], { type: type.ren_wu });
    const oldFa = _.find(currentData[user.num], { type: type.fa_bao });
    // console.log('oldRen:', oldRen)
    // console.log('oldFa:', oldFa)
    newData[user.num] = [];
    if (user.type === type.ren_wu) {
      newData[user.num].push(user);
      if (oldFa) {
        newData[user.num].push(oldFa);
      }
    }
    if (user.type === type.fa_bao) {
      if (oldRen) {
        newData[user.num].push(oldRen);
      }
      newData[user.num].push(user);
    }
    // console.log('user:', user)
    // console.log('newData:', newData)
    commit(SET_CURRENTDATA, newData);
  },
  deleteCard({ state, commit }: any, obj: any) {
    commit(DELETE_CURRENTDATA, obj);
  },
  fullLevelXiu({ state, commit }: any) {
    const { currentData } = state;
    const newData = _.map(currentData, (arr: any) => _.map(arr, (obj: any) => ({
      ...obj,
      levelXiu: 70,
    })));
    commit(SET_CURRENTDATA, newData);
  },
  fullLevelDu({ state, commit }: any) {
    const { currentData } = state;
    const newData = _.map(currentData, (arr: any) => _.map(arr, (obj: any) => ({
      ...obj,
      levelDu: 12,
    })));
    commit(SET_CURRENTDATA, newData);
  },
  fullLevelJu({ state, commit }: any) {
    const { currentData } = state;
    const newData = _.map(currentData, (arr: any) => _.map(arr, (obj: any) => {
      if (obj.character === characterType.jue_ding || obj.character === characterType.chao_fan) {
        return {
          ...obj,
          levelJu: 12,
          juChecked: true,
        };
      }
      return obj;
    }));
    commit(SET_CURRENTDATA, newData);
  },
  emptyCurrentData({ commit }: any) {
    commit(SET_CURRENTDATA, [[], [], [], [], [], [], [], []]);
  },
  saveCurrent({ state, commit }: any, name: string) {
    const { currentData } = state;
    commit(SAVE_MY_CARD, {
      id: uuid.v4(),
      name,
      data: currentData,
      saveTime: dayjs().format('YYYY-MM-DD HH:mm:ss'),
    });
  },
  saveToMyCard({ state, commit }: any, {name, data}: { name: string, data: any}) {
    commit(SAVE_MY_CARD, {
      id: uuid.v4(),
      name,
      data,
      saveTime: dayjs().format('YYYY-MM-DD HH:mm:ss'),
    });
  },
  deleteMyCard({ state, commit }: any, { id, index }: { id: string, index: number }) {
    const { myCard } = state;
    // console.log('id:', id);
    // console.log('index:', index);
    if (!_.isEmpty(id)) {
      const newMyCard = _.filter(myCard, (v: any) => v.id !== id);
      commit(SET_MY_CARD, newMyCard);
      return;
    }
    if (_.isNumber(index)) {
      myCard.splice(index, 1);
      commit(SET_MY_CARD, myCard);
    }
  },
  useMyCard({ state, commit }: any, { id, index }: { id: string, index: number }) {
    const { myCard } = state;
    if (!_.isEmpty(id)) {
      const newMyCard = _.filter(myCard, (v: any) => v.id === id);
      commit(SET_CURRENTDATA, newMyCard[0].data);
      commit(SAVE_HOME_ACTIVE_NAME, 'second');
      return;
    }
    if (_.isNumber(index)) {
      commit(SET_CURRENTDATA, myCard[index].data);
      commit(SAVE_HOME_ACTIVE_NAME, 'second');
    }
  },
  selectCalculatorCard({ state, commit }: any, user: {
    num: number, type: string, name: string,
    levelXiu: number, levelDu: number, levelJu: number, juChecked: boolean
  }) {
    const { calculator: { initData } } = state;
    const newData = [...initData];
    const oldRen = _.find(initData[user.num], { type: type.ren_wu });
    const oldFa = _.find(initData[user.num], { type: type.fa_bao });
    newData[user.num] = [];
    if (user.type === type.ren_wu) {
      newData[user.num].push(user);
      if (oldFa) {
        newData[user.num].push(oldFa);
      }
    }
    if (user.type === type.fa_bao) {
      if (oldRen) {
        newData[user.num].push(oldRen);
      }
      newData[user.num].push(user);
    }
    commit(SET_CALCULATOR_INITDATA, newData);
  },
  deleteCalculatorCard({ state, commit }: any, obj: any) {
    commit(DELETE_CALCULATOR_INITDATA, obj);
  },
  counterIt({ state, commit }: any, data: any){
    commit(SET_CALCULATOR_INITDATA, data);
    commit(SAVE_HOME_ACTIVE_NAME, 'third');
  },
  SETCALCULATORGENERALDATA({ state, commit }: any, data: any){
    commit(SET_CALCULATOR_GENERALDATA, data)
  },
  SETCALCULATOREXTREMITYDATA({ state, commit }: any, data: any){
    commit(SET_CALCULATOR_EXTREMITYDATA, data)
  }
};

export default actions;
